import sys, os, openpyxl
sys.stdout.reconfigure(encoding='utf-8')

wb_path = os.path.join(os.path.dirname(os.path.dirname(__file__)), '【IWE】产品信息包-20260428.xlsx')
wb = openpyxl.load_workbook(wb_path, data_only=True)

for sn in wb.sheetnames:
    ws = wb[sn]
    print(f'\n===== {sn} =====')
    print(f'  Dimensions: {ws.dimensions}')
    print(f'  Max row: {ws.max_row}, Max col: {ws.max_column}')
    print(f'  Merged cells: {list(ws.merged_cells.ranges)[:10]}')

    hidden_cols = []
    for col_letter in range(1, ws.max_column + 1):
        col_dim = ws.column_dimensions.get(openpyxl.utils.get_column_letter(col_letter))
        if col_dim and col_dim.hidden:
            hidden_cols.append(openpyxl.utils.get_column_letter(col_letter))
    if hidden_cols:
        print(f'  Hidden columns: {hidden_cols}')

    hidden_rows = []
    for r in range(1, min(ws.max_row + 1, 200)):
        row_dim = ws.row_dimensions.get(r)
        if row_dim and row_dim.hidden:
            hidden_rows.append(r)
    if hidden_rows:
        print(f'  Hidden rows: {hidden_rows[:20]}...' if len(hidden_rows) > 20 else f'  Hidden rows: {hidden_rows}')

    # For sheets with content, sample some cells with actual values
    if sn in ['2.Product Info（20260409更新）', '3.Message House（20260326更新）', '4.SPEC（20260428更新）']:
        # Check if there are more columns than we read
        for row in ws.iter_rows(min_row=1, max_row=5, values_only=False):
            for cell in row:
                if cell.value is not None:
                    print(f'  Cell {cell.coordinate}: {str(cell.value)[:80]}')

    if sn == '5.产品规格书':
        # Check all cells for any actual content
        content_cells = 0
        for row in ws.iter_rows(values_only=False):
            for cell in row:
                if cell.value is not None and cell.column > 3:
                    content_cells += 1
                    if content_cells <= 10:
                        print(f'  Content cell {cell.coordinate}: {str(cell.value)[:100]}')
        print(f'  Total content cells (col > 3): {content_cells}')

import sys, os, openpyxl
sys.stdout.reconfigure(encoding='utf-8')

wb_path = os.path.join(os.path.dirname(os.path.dirname(__file__)), '【IWE】产品信息包-20260428.xlsx')
wb = openpyxl.load_workbook(wb_path, data_only=True)

target_sheets = [
    '3.Message House（20260326更新）',
    '2.Product Info（20260409更新）',
    '4.SPEC（20260428更新）',
]

for sn in target_sheets:
    ws = wb[sn]
    print(f'\n===== {sn} (cols up to {ws.max_column}) =====')

    # Find all columns that have at least one non-empty cell
    col_has_data = {}
    for row in ws.iter_rows(values_only=False):
        for cell in row:
            if cell.value is not None:
                col_letter = openpyxl.utils.get_column_letter(cell.column)
                if col_letter not in col_has_data:
                    col_has_data[col_letter] = 0
                col_has_data[col_letter] += 1

    print(f'  Columns with data: { {k: v for k, v in sorted(col_has_data.items())} }')

    # For Message House, print rows that have data in columns L-O
    if 'Message House' in sn:
        print('\n  --- Extra columns (L-O) content ---')
        for row in ws.iter_rows(min_col=12, max_col=15, values_only=False):
            for cell in row:
                if cell.value is not None:
                    val = str(cell.value).replace('\n', ' | ')
                    print(f'  {cell.coordinate}: {val[:200]}')

    # For Product Info, check column N
    if 'Product Info' in sn:
        print('\n  --- Column N content ---')
        for row in ws.iter_rows(min_col=14, max_col=14, values_only=False):
            for cell in row:
                if cell.value is not None:
                    val = str(cell.value).replace('\n', ' | ')
                    print(f'  {cell.coordinate}: {val[:200]}')
